# The transformation code: safely extract data.user.id, assign to user_id
TRANSFORM_CODE='addHandler("transform", (request, context) => {
  request.body = request.body || {};
  request.body.user_id = request.body?.data?.user?.id ?? null;
  return request;
});'

hookdeck gateway connection create \
  --name "safe-transform-conn-${RUN_ID}" \
  --source-type WEBHOOK \
  --source-name "safe-transform-src-${RUN_ID}" \
  --destination-type MOCK \
  --destination-name "safe-transform-dest-${RUN_ID}" \
  --rule-transform-code "$TRANSFORM_CODE" \
  --output json 2>&1

